const items = $input.all();
const sender = String($('set_data').first().json.sender || '').trim();

const yaExiste = items.some(it => {
  const a = it.json || {};
  return String(a.telefono_principal || '').trim() === sender
      || String(a.telefono_alternativo || '').trim() === sender;
});

if (sender && yaExiste) {
  return [];
}

return [{
  json: {
    valido: true,
    resultado: 'OK',
    nuevo_id_alumno: Date.now(),
    sender,
    detalle: 'Alta nueva. id_alumno por epoch ms. Alumnos leidos: ' + items.length + '.'
  }
}];

let id_alumno = 'idle';

// Intentar obtener de check_status1
try {
  const temp = $('get_new_id').first().json?.nuevo_id_alumno;
  if (temp) id_alumno = temp;
} catch (error) {
  // Nodo no ejecutado, continuar
}

// Si no se obtuvo, intentar check_status
if (id_alumno === 'idle') {
  try {
    const temp = $('student_is_registred').first().json?.id_alumno;
    if (temp) id_alumno = temp;
  } catch (error) {
    // Nodo no ejecutado, usar default
  }
}

return [{ json: { id_alumno } }];

if (
  ($input.first().json.body.event === 'message_created')
    &&( (($input.first().json.body.conversation.messages[0].sender_type === null) || (String($input.first().json.body.conversation.messages[0].sender_type || '').toLowerCase() === 'contact') || (String($input.first().json.body.conversation.messages[0].sender.name || '').toLowerCase() === 'administracion')))
)
{
  return [{ json: {important: true}}];
}
else {
  return [{ json: {important: false}}];
}
